final:
module RefModule(in1, in2, in3, sum, carry);input in1 , in2, in3;
	output sum, carry;

	wire in1XORin2;

	assign in1XORin2 = in1 ^ in2;
	assign sum = in1XORin2 ^ in3;
  wire temp1_(in1 & in2) = (in1 & in2);
  wire temp2_(in3 &in1XORin2) = (in3 &in1XORin2);
  assign carry = (temp1_(in1 & in2) | temp2_(in3 &in1XORin2));endmodule
